<?php
 namespace WPAICG\ContentWriter; use SplQueue; if (!defined('ABSPATH')) { exit; } class AIPKit_Image_Injector { public function inject_images(string $content, array $images, string $placement, int $param_x = 2, string $alignment = 'none', string $image_size = 'large'): string { if (empty($images) || empty(trim($content))) { return $content; } switch ($placement) { case 'after_first_h2': return $this->inject_after_first_h2($content, $images, $alignment, $image_size); case 'after_first_h3': return $this->inject_after_first_h3($content, $images, $alignment, $image_size); case 'after_every_x_h2': return $this->inject_after_every_x_heading($content, $images, $param_x, 'h2', $alignment, $image_size); case 'after_every_x_h3': return $this->inject_after_every_x_heading($content, $images, $param_x, 'h3', $alignment, $image_size); case 'after_every_x_p': return $this->inject_after_every_x_paragraph($content, $images, $param_x, $alignment, $image_size); case 'at_end': return $this->inject_at_end($content, $images, $alignment, $image_size); default: return $this->inject_after_first_h2($content, $images, $alignment, $image_size); } } private function inject_after_first_h2(string $content, array $images, string $alignment, string $image_size): string { $image_html_array = array_filter( array_map(fn ($img) => $this->get_image_html($img, $alignment, $image_size), $images) ); if (empty($image_html_array)) { return $content; } $first_image = array_shift($image_html_array); $position = stripos($content, '</h2>'); if ($position !== false) { $content = substr_replace($content, '</h2>' . "\n\n" . $first_image . "\n\n", $position, 5); } else { $content .= "\n\n" . $first_image; } if (!empty($image_html_array)) { $content .= "\n\n" . implode("\n\n", $image_html_array); } return $content; } private function inject_after_first_h3(string $content, array $images, string $alignment, string $image_size): string { $image_html_array = array_filter( array_map(fn ($img) => $this->get_image_html($img, $alignment, $image_size), $images) ); if (empty($image_html_array)) { return $content; } $first_image = array_shift($image_html_array); $position = stripos($content, '</h3>'); if ($position !== false) { $content = substr_replace($content, '</h3>' . "\n\n" . $first_image . "\n\n", $position, 5); } else { $content .= "\n\n" . $first_image; } if (!empty($image_html_array)) { $content .= "\n\n" . implode("\n\n", $image_html_array); } return $content; } private function inject_after_every_x_heading(string $content, array $images, int $x, string $heading_tag, string $alignment, string $image_size): string { if ($x <= 0) { return $this->inject_at_end($content, $images, $alignment, $image_size); } $image_html_array = array_map(fn ($img) => $this->get_image_html($img, $alignment, $image_size), $images); $image_queue = new SplQueue(); foreach ($image_html_array as $img_html) { $image_queue->enqueue($img_html); } if ($image_queue->isEmpty()) { return $content; } $parts = preg_split('/(<\/' . $heading_tag . '>)/i', $content, -1, PREG_SPLIT_DELIM_CAPTURE); $new_content = ''; $heading_count = 0; foreach ($parts as $i => $part) { $new_content .= $part; if ($i > 0 && ($i % 2) !== 0) { $heading_count++; if ($heading_count % $x === 0 && !$image_queue->isEmpty()) { $new_content .= "\n\n" . $image_queue->dequeue() . "\n\n"; } } } while (!$image_queue->isEmpty()) { $new_content .= "\n\n" . $image_queue->dequeue(); } return $new_content; } private function inject_after_every_x_paragraph(string $content, array $images, int $x, string $alignment, string $image_size): string { if ($x <= 0) { return $this->inject_at_end($content, $images, $alignment, $image_size); } $image_html_array = array_map(fn ($img) => $this->get_image_html($img, $alignment, $image_size), $images); $image_queue = new SplQueue(); foreach ($image_html_array as $img_html) { $image_queue->enqueue($img_html); } if ($image_queue->isEmpty()) { return $content; } $parts = preg_split('/(<\/p>)/i', $content, -1, PREG_SPLIT_DELIM_CAPTURE); $new_content = ''; $p_count = 0; foreach ($parts as $i => $part) { $new_content .= $part; if ($i > 0 && ($i % 2) !== 0) { $p_count++; if ($p_count % $x === 0 && !$image_queue->isEmpty()) { $new_content .= "\n\n" . $image_queue->dequeue() . "\n\n"; } } } while (!$image_queue->isEmpty()) { $new_content .= "\n\n" . $image_queue->dequeue(); } return $new_content; } private function inject_at_end(string $content, array $images, string $alignment, string $image_size): string { $image_html_array = array_map(fn ($img) => $this->get_image_html($img, $alignment, $image_size), $images); return $content . "\n\n" . implode("\n\n", $image_html_array); } private function get_image_html(?array $image_item, string $alignment = 'none', string $image_size = 'large'): string { if (empty($image_item)) { return ''; } if (empty($image_item['attachment_id'])) { $fallback_url = $image_item['media_library_url'] ?? ($image_item['url'] ?? ($image_item['src'] ?? ($image_item['image_url'] ?? null))); if (empty($fallback_url)) { return ''; } $fallback_alt = $this->get_image_item_alt($image_item); if ($fallback_alt === '') { $fallback_alt = $image_item['revised_prompt'] ?? 'Image'; } $class_list = []; if (in_array($alignment, ['left', 'right', 'center', 'none'], true)) { $class_list[] = 'align' . $alignment; } $class_list[] = 'aipkit_cw_external_image'; $class_list[] = 'size-full'; $final_classes = esc_attr(implode(' ', $class_list)); return sprintf('<img class="%s" src="%s" alt="%s" />', $final_classes, esc_url($fallback_url), esc_attr($fallback_alt) ); } $attachment_id = absint($image_item['attachment_id']); $stored_alt = get_post_meta($attachment_id, '_wp_attachment_image_alt', true); $item_alt = $this->get_image_item_alt($image_item); $fallback_alt = $item_alt !== '' ? $item_alt : ($image_item['revised_prompt'] ?? get_the_title($attachment_id) ?: 'Image'); $alt_text = esc_attr($stored_alt ?: $fallback_alt); $image_attributes = wp_get_attachment_image_src($attachment_id, $image_size); if (!$image_attributes) { $image_attributes = wp_get_attachment_image_src($attachment_id, 'full'); if (!$image_attributes) { $url = esc_url($image_item['media_library_url'] ?? ''); $width_attr = ''; $height_attr = ''; $size_class = 'size-full'; } else { list($url, $width, $height) = $image_attributes; $url = esc_url($url); $width_attr = sprintf(' width="%d"', $width); $height_attr = sprintf(' height="%d"', $height); $size_class = 'size-full'; } } else { list($url, $width, $height) = $image_attributes; $url = esc_url($url); $width_attr = sprintf(' width="%d"', $width); $height_attr = sprintf(' height="%d"', $height); $size_class = 'size-' . esc_attr($image_size); } $class_list = []; if (in_array($alignment, ['left', 'right', 'center', 'none'], true)) { $class_list[] = 'align' . $alignment; } $class_list[] = 'wp-image-' . $attachment_id; $class_list[] = $size_class; $final_classes = esc_attr(implode(' ', $class_list)); return sprintf('<img class="%s" src="%s" alt="%s"%s%s />', $final_classes, $url, $alt_text, $width_attr, $height_attr ); } private function get_image_item_alt(array $image_item): string { foreach (['alt', 'alt_text', 'generated_alt_text', 'image_alt', 'seo_alt'] as $key) { if (!empty($image_item[$key]) && is_scalar($image_item[$key])) { return trim(wp_strip_all_tags((string) $image_item[$key])); } } return ''; } } 